import axios from 'axios';

const TOKEN = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..WuGPaULWfvrWqdJBS-JLTtb15Y6IJaPKIV4X1zZ630s';
const API_BASE = 'https://api.talesofai.cn';

const client = axios.create({
  baseURL: API_BASE,
  headers: {
    'x-token': TOKEN,
    'x-platform': 'web',
    'x-nieta-app-version': '6.8.8',
  },
});

async function main() {
  const hashtagName = '捏捏开荒团';
  
  const feedRes = await client.get('/v1/home/feed/mainlist', {
    params: {
      theme: hashtagName,
      page_index: 0,
      page_size: 5
    }
  });
  
  const modules = feedRes.data.module_list || [];
  
  console.log('=== 第一条 module 的完整 json_data ===\n');
  const firstModule = modules.find(m => m.template_id === 'NORMAL');
  if (firstModule) {
    console.log(JSON.stringify(firstModule.json_data, null, 2));
  }
}

main();
